ee:message.ee:set-payload:
%dw 2.0 output application/java
var ctx = vars.plantContext var top = vars.scoredIdeas[0] default { ideaName: "Headcount Right-Sizing", ideaCategory: "Workforce", typicalFTEMin: 0.5, typicalFTEMax: 1.5, effort: "Medium", benchmarkCount: 0, benchmarkEvidence: "No cross-plant benchmarks available", score: 0 }
var fteImpact = top.typicalFTEMin default 0.5 var dollarImpact = fteImpact * 130000 var confidence = if ((top.benchmarkCount default 0) > 2) 88 else if ((top.benchmarkCount default 0) > 0) 74 else 62
var validations = (if (top.effort == "High") "Safety Review, Finance Approval, Quality Sign-off" else "Finance Approval, Safety Review") --- { selectedIdeaName: top.ideaName, fteImpact: fteImpact, dollarImpact: dollarImpact, confidenceScore: confidence, effort: if (['Low', 'Medium', 'High'] contains (top.effort default "")) top.effort else "Medium", reasoning: "Based on " ++ ((top.benchmarkCount default 0) as String) ++ " cross-plant benchmarks, this idea is the highest-scoring match for the " ++ ctx.shopName ++ " " ++ ctx.recentSignalType ++ " signal. Targeting a " ++ (ctx.gapToTarget as String) ++ " FTE reduction gap in " ++ ctx.quarter ++ ".", requiredValidations: validations, rawLlmResponse: "[DataWeave scoring engine — Einstein Prompt Template requires org-level Prompt Builder configuration]" }

%dw 2.0
output application/json
var ctx  = vars.plantContext
var rec  = vars.recommendation
var top  = vars.scoredIdeas[0] default {}
var idea = vars.ideaId default "unknown"
---
{
    blocks: [
        {
            'type': "header",
            text: {
                'type': "plain_text",
                text: ":factory: PlantIQ AI Recommendation — " ++ ctx.plantName
            }
        },
        {
            'type': "section",
            fields: [
                { 'type': "mrkdwn", text: "*Shop:*\n"        ++ ctx.shopName },
                { 'type': "mrkdwn", text: "*Quarter:*\n"     ++ ctx.quarter },
                { 'type': "mrkdwn", text: "*HQ Gap:*\n"      ++ (ctx.gapToTarget as String) ++ " FTE" },
                { 'type': "mrkdwn", text: "*Confidence:*\n"  ++ (rec.confidenceScore as String) ++ "%" }
            ]
        },
        {
            'type': "section",
            text: {
                'type': "mrkdwn",
                text: "*Recommended Idea:* " ++ rec.selectedIdeaName ++
                      "\n*FTE Impact:* " ++ (rec.fteImpact as String) ++
                      " FTE  |  *USD Impact:* " ++ (rec.dollarImpact as String) ++
                      "\n*Effort:* " ++ (rec.effort default "Medium") ++
                      "\n*Evidence:* " ++ (top.benchmarkEvidence default "No benchmarks available") ++
                      "\n*Reasoning:* " ++ (rec.reasoning default "")
            }
        },
        {
            'type': "actions",
            elements: [
                {
                    'type': "button",
                    text: { 'type': "plain_text", text: "Approve" },
                    style: "primary",
                    action_id: "approve_idea",
                    value: idea
                },
                {
                    'type': "button",
                    text: { 'type': "plain_text", text: "Reject" },
                    style: "danger",
                    action_id: "reject_idea",
                    value: idea
                },
                {
                    'type': "button",
                    text: { 'type': "plain_text", text: "More Info" },
                    action_id: "more_info_idea",
                    value: idea
                }
            ]
        }
    ]
}
